// PREPARAR TEXTO PARA MEMORIA VECTORIAL (Pinecone)
// Usa los campos del Format Final Columns (nombres reales de columnas)
const item = $input.first ? $input.first() : { json: $input.item.json };
const json = item.json;

const textoParaVector = [
  'EMPRESA: ' + (json['COMPANY NAME'] || ''),
  'PAÍS: ' + (json['PAÍS'] || ''),
  'LÍNEA: ' + (json['LÍNEA DE NEGOCIO'] || ''),
  'TIER: ' + (json['TIER'] || ''),
  'RADAR: ' + (json['RADAR ACTIVO SI/NO'] || 'No'),
  'TIPO SEÑAL: ' + (json['TIPO DE SEÑAL DE INVERSIÓN'] || ''),
  'DESCRIPCIÓN: ' + (json['DESCRIPCIÓN DE SEÑAL (RESUMEN)'] || ''),
  'FUENTE: ' + (json['FUENTE DE LA SEÑAL'] || ''),
  'SCORE: ' + (json['SCORE RADAR'] || 0),
  'FECHA: ' + (json['Fecha Escaneo'] || '')
].join('\n');

return {
  json: {
    ...json,
    pageContent: textoParaVector,
    empresa: json['COMPANY NAME'],
    pais: json['PAÍS'],
    descripcion: json['DESCRIPCIÓN DE SEÑAL (RESUMEN)'],
    titulo: (json['TIPO DE SEÑAL DE INVERSIÓN'] || '') + ' - ' + (json['COMPANY NAME'] || ''),
    validacion_razon: json['_qa_status'] || 'OK'
  }
};

// ═══ NORMALIZADOR + PRIORIDAD DE FUENTES v3 (con relevancia empresa) ═══
// v3: Penaliza resultados que NO mencionan el nombre de la empresa en título+snippet

const item = $input.item.json;
const raw = item.results || item.organic || [];
const nombreEmpresa = (item.empresa || '').toLowerCase();

const DOMAIN_PRIORITY = {
  'bnamericas.com': 1000,
  'ijglobal.com': 900,
  'secop.gov.co': 820, 'aerocivil.gov.co': 820, 'mincit.gov.co': 810,
  'dnp.gov.co': 810, 'infraestructura.gov.co': 810, 'mintransporte.gov.co': 800,
  'ccr.com.br': 750, 'bndes.gov.br': 750, 'anac.gov.br': 740,
  'sat.gob.mx': 720, 'sct.gob.mx': 720, 'aeropuertos.gov.ar': 720,
  'latitude-15.com': 700,
  'airportscouncil.org': 680,
  'aci-lac.aero': 680,
  'bolsadesantiago.com': 680, 'bmv.com.mx': 680, 'bvl.com.pe': 680,
  'bloomberg.com': 620, 'reuters.com': 620, 'ft.com': 600,
  'constructiondive.com': 560, 'portafolio.co': 540,
  'eltiempo.com': 500, 'elcolombiano.com': 480,
  'semana.com': 460, 'dinero.com': 460,
  'infobae.com': 430, 'clarin.com': 400,
  'linkedin.com': 350,
  'aviationweek.com': -200, 'avweb.com': -200,
  'skybrary.aero': -300, 'airlineratings.com': -200,
  'wikipedia.org': -500, 'reddit.com': -500, 'quora.com': -500,
};

const getDomainPriority = (url) => {
  if (!url) return 0;
  try {
    const hostname = new URL(url).hostname.replace('www.', '');
    if (DOMAIN_PRIORITY[hostname] !== undefined) return DOMAIN_PRIORITY[hostname];
    if (hostname.match(/\.gov\./) || hostname.endsWith('.gov')) return 760;
    for (const [domain, score] of Object.entries(DOMAIN_PRIORITY)) {
      if (hostname.includes(domain.split('.')[0])) return score;
    }
  } catch(e) {}
  return 0;
};

const mentionsEmpresa = (r) => {
  if (!nombreEmpresa || nombreEmpresa.length < 3) return true; // fallback si no hay nombre
  const text = ((r.title || '') + ' ' + (r.content || r.snippet || '')).toLowerCase();
  // Match primero 2 palabras del nombre (ej: "grupo bimbo" en "Grupo Bimbo anunció")
  const words = nombreEmpresa.split(' ').filter(w => w.length > 2);
  if (words.length === 0) return true;
  // Al menos las primeras 2 palabras significativas deben aparecer
  const key = words.slice(0, 2).join(' ');
  return text.includes(key) || text.includes(words[0]);
};

const normalizeItem = (r) => {
  const url = r.url || r.link || '';
  let domain = '';
  try { domain = new URL(url).hostname.replace('www.', ''); } catch(e) {}
  const mentioned = mentionsEmpresa(r);
  return {
    title: r.title || '',
    link: url,
    snippet: r.content ? r.content.substring(0, 500) : (r.snippet || ''),
    date: r.published_date || r.date || '',
    source: domain || r.source || '',
    score: r.score || 0,
    _domain_priority: getDomainPriority(url),
    _mentions_empresa: mentioned   // tag para debug en ejecución
  };
};

// Ordenar: empresa-específico primero, genérico después
const organic = raw
  .map(normalizeItem)
  .filter(r => r.link && r.title)
  .sort((a, b) => {
    // Si solo uno menciona la empresa, ese va primero
    if (a._mentions_empresa && !b._mentions_empresa) return -1;
    if (!a._mentions_empresa && b._mentions_empresa) return 1;
    // Si ambos igual (ambos mencionan o ambos no), usar prioridad de dominio + score tavily
    const scoreA = (a._domain_priority * 0.7) + (a.score * 300);
    const scoreB = (b._domain_priority * 0.7) + (b.score * 300);
    return scoreB - scoreA;
  })
  .slice(0, 10);

return {
  ...item,
  organic,
  tavily_answer: item.answer || ''
};

// ═══ VALIDADOR DE FUENTES — Checks determinísticos ═══
// Verifica si la señal tiene respaldo real antes de llamar al AI Validador.
// Referencia los organic[] de Tavily para confirmar URLs y convergencia.

const output = $json.output || $json;
const organic = $('Code in JavaScript5').item.json.organic || [];

const PREMIUM_DOMAINS = [
  'bnamericas.com', 'secop.gov.co', 'aerocivil.gov.co', 'anac.gob.ar',
  'mincit.gov.co', 'dnp.gov.co', 'infraestructura.gov.co', 'ccr.com.br',
  'linkedin.com', 'bolsadesantiago.com', 'bmv.com.mx', 'bvl.com.pe',
  'aeroportos.gov.br', 'caasd.gov.do', 'dgac.gob.cl', 'iaac.int',
  'aena.es', 'bndes.gov.br', 'iata.org', 'aci.aero'
];

const INVERSION_KEYWORDS = [
  'capex', 'invers', 'construc', 'licitaci', 'ampliac',
  'modernizac', 'proyecto', 'terminal', 'planta', 'cedi',
  'expansion', 'contrat', 'adjudic', 'concesion', 'habilitac'
];

const COMPLETED_WORDS = [
  'inauguro', 'inaugurado', 'fue entregado', 'ya opera',
  'abrio sus puertas', 'fue completado', 'termino su construccion',
  'finalizo', 'en operacion desde', 'fue inaugurado', 'completado'
];

const normalize = s => String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const radarActivo = output?.radar_activo === 'Sí' || output?.radar_activo === 'Si';
const fuenteLink = normalize(output?.fuente_link || '');
const empresaNorm = normalize(output?.empresa_evaluada || '').substring(0, 25);

// ─── Sin señal: auto-aprobado ─────────��────��─────��───────────────
if (!radarActivo) {
  return [{
    json: {
      ...output,
      _val_precheck: 'Auto-Aprobado',
      _val_motivo: 'Sin señal activa — validación no requerida',
      _url_verificada: false,
      _fuente_premium: false,
      _convergencia: 0
    }
  }];
}

// ─������� Checks para señales positivas ─────────��───────────────────
// 1. ¿La URL reportada existe en los resultados de Tavily?
const organicUrls = organic.map(r => normalize(r.link || ''));
const fuenteIs40  = fuenteLink.substring(0, 40);
const urlVerificada = fuenteLink !== 'no disponible' &&
  fuenteLink.startsWith('http') &&
  organicUrls.some(u => u.includes(fuenteIs40));

// 2. ��El dominio es premium/oficial?
let fuente_premium = false;
try {
  const url = new URL(output.fuente_link || '');
  const domain = url.hostname.replace('www.', '');
  fuente_premium = PREMIUM_DOMAINS.some(d => domain.includes(d));
} catch(e) {}

// 3. ¿Cuántos snippets mencionan la empresa + keywords de inversión?
const convergencia = organic.filter(r => {
  const text = normalize((r.snippet || '') + ' ' + (r.title || ''));
  return text.includes(empresaNorm.substring(0, 15)) &&
    INVERSION_KEYWORDS.some(k => text.includes(k));
}).length;

// 4. ¿Algún snippet menciona proyecto completado?
const proyectoCompletado = organic.some(r => {
  const text = normalize((r.snippet || '') + ' ' + (r.title || ''));
  return COMPLETED_WORDS.some(w => text.includes(w));
});

// 5. ¿URL claramente inventada?
const urlInventada = fuenteLink !== 'no disponible' &&
  fuenteLink.startsWith('http') &&
  !urlVerificada;

// ─── Clasificación ──────────────────────────────────���────────────
let _val_precheck, _val_motivo;

if (proyectoCompletado) {
  _val_precheck = 'Observado';
  _val_motivo   = 'Snippets sugieren proyecto ya completado o inaugurado';
} else if (urlInventada) {
  _val_precheck = 'Observado';
  _val_motivo   = `URL no encontrada en resultados Tavily: ${output.fuente_link}`;
} else if (fuente_premium && convergencia >= 1) {
  _val_precheck = 'Aprobado';
  _val_motivo   = `Fuente premium (${output.fuente_nombre || 'oficial'}) + ${convergencia} snippet(s) confirmando`;
} else if (convergencia >= 2) {
  _val_precheck = 'Aprobado';
  _val_motivo   = `${convergencia} snippets independientes confirman la inversión`;
} else if (urlVerificada && convergencia >= 1) {
  _val_precheck = 'Aprobado';
  _val_motivo   = 'URL verificada en organic[] + al menos 1 snippet relevante';
} else if (fuenteLink === 'no disponible') {
  _val_precheck = 'Borderline';
  _val_motivo   = 'Sin URL reportada — enviando a validación IA para revisar snippets';
} else {
  _val_precheck = 'Borderline';
  _val_motivo   = `Fuente no premium, convergencia baja (${convergencia}) — enviando a validación IA`;
}

return [{
  json: {
    ...output,
    _val_precheck,
    _val_motivo,
    _url_verificada: urlVerificada,
    _fuente_premium: fuente_premium,
    _convergencia: convergencia,
    _proyecto_completado: proyectoCompletado
  }
}];

