// PREPARAR TEXTO PARA MEMORIA VECTORIAL (Pinecone)
// Usa los campos del Format Final Columns (nombres reales de columnas)
const item = $input.first ? $input.first() : { json: $input.item.json };
const json = item.json;

const textoParaVector = [
  'EMPRESA: ' + (json['COMPANY NAME'] || ''),
  'PAÍS: ' + (json['PAÍS'] || ''),
  'LÍNEA: ' + (json['LÍNEA DE NEGOCIO'] || ''),
