// ═══ FUSIONAR RESULTADO DE VALIDACIÓN ═══
// Combina la conclusión del AI Validador con los datos del radar original.
// Output: objeto plano con todos los campos para el If de routing.

const radarData = $('AI Agent RADAR1').item.json.output || {};
const valData   = $json.output || $json; // Resultado del AI Agente Validador
const preData   = $('Validador de Fuentes1').item.json;

return [{
  json: {
    // Campos del radar (base)
    ...radarData,
    // Pre-check determinístico
    _val_precheck:       preData._val_precheck || 'Borderline',
    _val_motivo_codigo:  preData._val_motivo   || '',
    _url_verificada:     preData._url_verificada || false,
    _fuente_premium:     preData._fuente_premium || false,
    _convergencia:       preData._convergencia   || 0,
    // Resultado de la validación IA
    validacion_estado:   valData.validacion_estado   || 'Observado',
    motivo_validacion:   valData.motivo_validacion   || '',
    links_validados:     JSON.stringify(valData.links_validados || []),
    links_rechazados:    JSON.stringify(valData.links_rechazados || []),
    confianza:           valData.confianza            || 'Baja',
    convergencia_count:  valData.convergencia_count   || 0
  }
}];

// ═══ FUSIONAR BÚSQUEDAS: Primarias + General ═══
// Etapa 1 (BNAmericas / Gov) llega desde 'Buscar Fuentes Primarias1'
// Etapa 2 (General)          llega desde el nodo actual ($json)

const primarias  = $('Buscar Fuentes Primarias').item.json.results || [];
const generales  = $input.item.json.results || [];
const answerGen  = $input.item.json.answer || '';

// Normalizar un resultado de Tavily a formato estándar
const normalize = (r, stage) => {
  const url = r.url || r.link || '';
  let domain = '';
  try { domain = new URL(url).hostname.replace('www.', ''); } catch(e) {}
  return {
    title:   r.title   || '',
    link:    url,
    snippet: (r.content || r.snippet || '').substring(0, 500),
    date:    r.published_date || r.date || '',
    source:  domain,
    score:   r.score || 0,
    _stage:  stage   // 'primaria' | 'general'
  };
};

// Combinar: Primarias primero, General después
const seenUrls = new Set();
const combined = [
  ...primarias.map(r => normalize(r, 'primaria')),
  ...generales.map(r => normalize(r, 'general'))
].filter(r => {
  if (!r.link || !r.title) return false;
  if (seenUrls.has(r.link)) return false;
  seenUrls.add(r.link);
  return true;
});

// Pasar al siguiente nodo con el formato esperado por Code JS5
return {
  ...$('Loop Over Items1').item.json,  // empresa, pais, linea, tier, tavily_query, etc.
  results: combined,
  answer: answerGen,
  _primarias_count: primarias.length,
  _generales_count: generales.length
};

// Normalizar Linea v2 — detecta la linea de negocio con NFD normalization
// FIX: el regex [^A-Za-z] no maneja acentos correctamente sin NFD.
//   "LÍNEA DE NEGOCIO" → LNEADENEGOCIO (Í descartada) �� no match.
//   Con NFD: "LI\u0301NEA..." → acento removido → LINEADENEGOCIO → match correcto.

// Función para normalizar una clave a ASCII
const normKey = k =>
  k.normalize('NFD')
   .replace(/[\u0300-\u036f]/g, '')  // quitar combining marks
   .replace(/[^A-Za-z]/g, '')           // quitar no-letras
   .toUpperCase();

// Buscar la clave que corresponde a Línea de Negocio
// Acepta: 'LÍNEA DE NEGOCIO', 'linea_negocio', 'LINEA DE NEGOCIO', etc.
const lineaKey = Object.keys($json).find(k => {
  const n = normKey(k);
  return n === 'LINEADENEGOCIO' || n === 'LINEANEGOCIO';
});

const rawLinea = lineaKey ? String($json[lineaKey]) : '';

console.log('[NormLinea-v2] lineaKey:', lineaKey, '| rawLinea:', rawLinea);

let _linea;
if (rawLinea.toUpperCase().includes('BHS')) {
  _linea = 'BHS';
} else if (rawLinea.normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^A-Za-z]/g,'').toUpperCase().includes('CART')) {
  _linea = 'Carton';
} else if (rawLinea.normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^A-Za-z]/g,'').toUpperCase().includes('INTRA')) {
  _linea = 'Intra';
} else {
  _linea = 'Intra'; // fallback
}

console.log('[NormLinea-v2] _linea:', _linea);

return { json: { ...$json, _linea } };

// === DETERMINAR SUB-LINEA v1.1 (fix: return format + normalize) ===
// Clasifica la empresa en su sub-linea especifica para enrutar al Excel correcto.
const e = $input.item.json;

function norm(s) {
  return (s || '').toLowerCase().normalize('NFD').replace(/̀-ͯ/g, '');
}

const nombre = norm(e.empresa || e.company_name || '');
const linea  = norm(e._linea || e.linea_negocio || '');
const sector = norm(e.sector || '');
const kws    = (e.keywords_usadas || '').toLowerCase();

let _sub_linea = 'INTRA_FINAL'; // default

if (linea === 'bhs' || linea.startsWith('bhs')) {
  const CARGO_SIGNALS = ['cargo','freight','carga','logistica aerea','air cargo','aerocarga'];
  const esCargo = CARGO_SIGNALS.some(function(s) {
    return nombre.indexOf(s) >= 0 || sector.indexOf(s) >= 0 || kws.indexOf(s) >= 0;
  });
  _sub_linea = esCargo ? 'BHS_CARGO' : 'BHS_AEROPUERTOS';

} else if (linea.indexOf('cart') >= 0 || linea.indexOf('papel') >= 0) {
  _sub_linea = 'CARTON';

} else if (linea.indexOf('intra') >= 0 || linea.indexOf('solumat') >= 0) {
  const SOLUMAT_SIGNALS = ['solumat','rack','estanteri'];
  const MOTOS_SIGNALS   = ['moto','motorcycle','motocicleta','yamaha','honda','suzuki','kawasaki','tvs','hero','bajaj'];

  if (SOLUMAT_SIGNALS.some(function(s) { return nombre.indexOf(s) >= 0 || sector.indexOf(s) >= 0; })) {
    _sub_linea = 'INTRA_SOLUMAT';
  } else if (MOTOS_SIGNALS.some(function(s) { return nombre.indexOf(s) >= 0 || sector.indexOf(s) >= 0; })) {
    _sub_linea = 'INTRA_MOTOS';
  } else {
    _sub_linea = 'INTRA_FINAL';
  }
}

return { json: Object.assign({}, e, { _sub_linea: _sub_linea }) };

// Parse RADAR1 Output v4 — handles AI Agent text output
const item = $input.item.json;

// Path B: already processed by Filtro (no-signal, output is object with radar_activo)
if (item.output && typeof item.output === 'object' && item.output.radar_activo) {
  return { json: item };
}

// Path A: from AI Agent — $json.output is a string (agent text response)
const rawOutput = item.output || '{}';
const text = typeof rawOutput === 'string' ? rawOutput : JSON.stringify(rawOutput);

// Extract JSON block (model might wrap in markdown or add extra text)
let jsonStr = text;
const jsonMatch = text.match(/\{[\s\S]*\}/);
if (jsonMatch) jsonStr = jsonMatch[0];

let output = {};
try {
  output = JSON.parse(jsonStr);
} catch(e) {
  output = {
    empresa_evaluada: '',
    linea_negocio: '',
    radar_activo: 'No',
    tipo_senal: 'Sin Señal',
    descripcion_resumen: 'Error al parsear respuesta del modelo.',
    fuente_link: 'No disponible',
    fuente_nombre: 'Sin Señal',
    fecha_senal: 'No disponible',
    ventana_compra: 'Sin señal',
    radar_6_12m: 'No',
    score_relevancia: 0,
    motivo_descarte: 'Error de parseo: ' + e.message
  };
}

// Guarantee empresa_evaluada and linea_negocio (needed by Validador downstream)
try {
  if (!output.empresa_evaluada) output.empresa_evaluada = $('Loop Over Items1').item.json.empresa || '';
  if (!output.linea_negocio) output.linea_negocio = $('Loop Over Items1').item.json.linea_negocio || '';
} catch(e) {}

return { json: { output } };

// === FILTRO MENCIONES EMPRESA v4 ===
const item = $input.item.json;
const empresa = item.empresa || '';
const organic = item.organic || [];
const linea = item.linea_negocio || '';

function normalizar(s) {
  return (s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
}

const empNorm = normalizar(empresa);
const palabras = empNorm.split(' ').filter(function(w) { return w.length > 2; });
const empKey1 = palabras.slice(0, 2).join(' ');
const empKey2 = palabras[0] || '';

const menciones = organic.filter(function(r) {
  const text = normalizar((r.title || '') + ' ' + (r.snippet || ''));
  if (!text || text.length < 5) return false;
  if (empNorm.length > 5 && text.indexOf(empNorm) >= 0) return true;
  if (empKey1.length > 5 && text.indexOf(empKey1) >= 0) return true;
  if (empKey2.length > 5 && text.indexOf(empKey2) >= 0) return true;
  return false;
});

const hasMenciones = menciones.length > 0;
console.log('[Filtro] ' + empresa + ': ' + menciones.length + '/' + organic.length + ' menciones → ' + (hasMenciones ? 'pasa a AI' : 'sin señal directo'));

if (!hasMenciones) {
  return {
    json: {
      ...item,
      _has_menciones: false,
      output: {
        empresa_evaluada: empresa,
        linea_negocio: linea,
        radar_activo: 'No',
        tipo_senal: 'Sin Señal',
        descripcion_resumen: 'No se encontraron fuentes específicas de la empresa en los resultados de búsqueda. Los artículos encontrados son sectoriales, nacionales o de otras empresas sin mención directa de ' + empresa + '.',
        fuente_link: 'No disponible',
        fuente_nombre: 'Sin Señal',
        fecha_senal: 'No disponible',
        ventana_compra: 'Sin señal',
        radar_6_12m: 'No',
        score_relevancia: 0,
        motivo_descarte: 'Ninguno de los ' + organic.length + ' resultados menciona específicamente a ' + empresa + '; artículos sectoriales, planes nacionales u otras empresas sin relación directa.'
      }
    }
  };
}

return {
  json: {
    ...item,
    _has_menciones: true,
    _menciones_count: menciones.length
  }
};

// Parse input from WF01 (Calificador) webhook or legacy webhook
// WF01 sends: { empresa, pais, linea_negocio, tier, company_domain, score_calificacion, segmentacion: {...} }
// Legacy sends: { empresas: [...] } or CSV-like structure
// N8N webhook wraps JSON body under .body key — handle both wrapped and direct

const raw = $input.all()[0]?.json || {};
const body = raw.body || raw;  // Fix: N8N v2 webhook wraps under .body

let empresas = [];

// Format A: single company from WF01 (has 'empresa' and 'score_calificacion')
if (body.empresa && body.score_calificacion !== undefined) {
  empresas = [{
    empresa:           body.empresa,
    pais:              body.pais || 'Colombia',
    linea_negocio:     body.linea_negocio || '',
    tier:              body.tier || 'MONITOREO',
    company_domain:    body.company_domain || '',
    score_calificacion: body.score_calificacion,
    // Pass through segmentation from WF01 (pre-calculated)
    'IMPACTO EN EL PRESUPUESTO': body.segmentacion?.impacto_presupuesto || '',
    'MULTIPLANTA':               body.segmentacion?.multiplanta          || '',
    'RECURRENCIA':               body.segmentacion?.recurrencia          || '',
    'REFERENTE DEL MERCADO':     body.segmentacion?.referente_mercado    || '',
    'ANIO OBJETIVO':             body.segmentacion?.anio_objetivo        || '',
    'TICKET ESTIMADO':           body.segmentacion?.ticket_estimado      || 'Sin ticket',
    'PRIORIDAD COMERCIAL':       body.segmentacion?.prioridad_comercial  || '',
  }];
}
// Format B: array of companies (batch or legacy)
else if (body.empresas && Array.isArray(body.empresas)) {
  empresas = body.empresas.map(e => ({
    empresa:        e.empresa || e.company_name || '',
    pais:           e.pais    || e.country      || 'Colombia',
    linea_negocio:  e.linea_negocio || '',
    tier:           e.tier    || 'Tier B',
    company_domain: e.company_domain || '',
    score_calificacion: e.score_calificacion || null,
    'PRIORIDAD COMERCIAL': e.prioridad_comercial || '',
  }));
}
// Format C: legacy body (has 'empresa' as single but no score - direct webhook)
else if (body.empresa) {
  empresas = [{
    empresa:        body.empresa,
    pais:           body.pais || 'Colombia',
    linea_negocio:  body.linea_negocio || '',
    tier:           body.tier || 'Tier B',
    company_domain: body.company_domain || '',
  }];
}

if (!empresas.length) {
  throw new Error('No companies found in webhook body. Expected {empresa,...} or {empresas:[...]}');
}

return empresas.map(e => ({ json: e }));
